#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205;
ll n,L,x[N],t[N],dp[N][N][N][2],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>L;
	for(int i=1;i<=n;i++)
	{
		cin>>x[i];
	}
	for(int i=1;i<=n;i++)
	{	
		cin>>t[i];
	}
	for(int l=0;l<=n;l++)
	{
		for(int r=0;r<=n;r++)
		{
			for(int k=0;k<=n;k++)
			{
				dp[l][r][k][0]=dp[l][r][k][1]=1e10;
//				cout << dp[l][r][k][0] << "aaa\n";
			}
		}
	}
	dp[0][0][0][0]=dp[0][0][0][1]=0;
	x[n+1]=L;
	for(int l=0;l<=n;l++)
	{
		for(int r=0;r<n-l;r++)
		{
			for(int k=0;k<=n;k++)
			{
//				cout<<l << " "<<r << " "<<k << " "<<dp[l][r][k][0]<<" "<<x[n-l+1] - x[n-l]<<"  aaa\n";
				bool flag=0;
				ll tmp=dp[l][r][k][0] + x[n-l+1] - x[n-l];
				if(tmp<=t[n-l]) flag=1;
				if(tmp<0)
				{
//					cout << tmp<< "aaaaaaa\n";
				}
				dp[l+1][r][k+flag][0]=min(dp[l+1][r][k+flag][0],tmp);

				flag=0;
				tmp=dp[l][r][k][0] +L + x[r+1] -x[n-l+1];
				if(tmp<0)
				{
//					cout<<l<< " "<<x[r+1] << " "<< x[n-l+1]<<"  bbb\n";
				}
				if(tmp<=t[r+1]) flag=1;
				dp[l][r+1][k+flag][1]=min(dp[l][r+1][k+flag][1],tmp);

				flag=0;
				tmp=dp[l][r][k][1] +L +x[r] -x[n-l];
				if(tmp<0)
				{
//					cout<<l +x[r] -x[n-l]<<"  ccc\n";
				}
				if(tmp<=t[n-l]) flag=1;
				dp[l+1][r][k+flag][0]=min(dp[l+1][r][k+flag][0],tmp);

				flag=0;
				tmp=dp[l][r][k][1] +x[r+1] -x[r];
				if(tmp<0)
				{
//					cout<<x[r+1] -x[r]<<"  ddd\n";
				}
				if(tmp<=t[r+1]) flag=1;
				dp[l][r+1][k+flag][1]=min(dp[l][r+1][k+flag][1],tmp);
			}
		}
	}
	for(int l=0;l<=n;l++)
	{
		for(int r=0;r<=n;r++)
		{
			for(int k=0;k<=n;k++)
			{
//				cout<<l<<" "<<r<<" "<<k<<" "<<dp[l][r][k][0]<<" "<<dp[l][r][k][1]<<"\n";
				if((dp[l][r][k][0]<1e10)||(dp[l][r][k][1]<1e10)) ans=max(ans,(ll)k);
			}
		}
	}
	cout<<ans;
	return 0;
}
